const e=document.getElementById("menu-toggle"),t=document.getElementById("mobile-menu"),o=document.getElementById("menu-icon"),d=document.getElementById("close-icon"),n=document.getElementById("navbar");e?.addEventListener("click",()=>{const s=!t?.classList.contains("hidden");t?.classList.toggle("hidden"),o?.classList.toggle("hidden"),d?.classList.toggle("hidden"),e.setAttribute("aria-expanded",String(!s))});window.addEventListener("scroll",()=>{window.scrollY>10?n?.classList.add("shadow-lg"):n?.classList.remove("shadow-lg")},{passive:!0});
